/**
 * Evolution Engine — 状态持久化
 *
 * 管理 suggestions/pending.json 和 history.jsonl。
 * 所有路径基于传入的 evolutionDir 参数，不硬编码。
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from "node:fs";
import { join } from "node:path";
import type { PendingFile, HistoryEntry, MetricsSnapshot, EvolutionSuggestion } from "./types.js";

// ── 内部路径 ─────────────────────────────────────────

function suggestionsPath(dir: string): string {
	return join(dir, "suggestions", "pending.json");
}

function historyPath(dir: string): string {
	return join(dir, "history.jsonl");
}

function metricsHistoryPath(dir: string): string {
	return join(dir, "metrics-history.json");
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 读取 pending.json。
 * 文件不存在或 JSON 损坏时返回 null。
 */
export function loadPending(dir: string): PendingFile | null {
	const filePath = suggestionsPath(dir);
	if (!existsSync(filePath)) return null;

	try {
		const raw = readFileSync(filePath, "utf-8");
		const pending = JSON.parse(raw) as PendingFile;

		// Migration: 旧格式有 diff 字段而无 instruction，自动迁移
		for (const sug of pending.suggestions) {
			if (!sug.instruction && (sug as unknown as Record<string, unknown>).diff) {
				sug.instruction = String((sug as unknown as Record<string, unknown>).diff);
				delete (sug as unknown as Record<string, unknown>).diff;
			}
		}

		return pending;
	} catch {
		return null;
	}
}

/**
 * 写入 pending.json。
 * 目录不存在时递归创建。
 */
export function savePending(dir: string, pending: PendingFile): void {
	const filePath = suggestionsPath(dir);
	const dirName = join(dir, "suggestions");

	if (!existsSync(dirName)) {
		mkdirSync(dirName, { recursive: true });
	}

	writeFileSync(filePath, JSON.stringify(pending, null, 2), "utf-8");
}

/**
 * 追加一条 JSON 行到 history.jsonl。
 * 文件不存在时创建。
 */
export function appendHistory(dir: string, entry: HistoryEntry): void {
	const filePath = historyPath(dir);

	appendFileSync(filePath, JSON.stringify(entry) + "\n", "utf-8");
}

/**
 * 读取 history.jsonl 最后 N 条记录。
 * 文件不存在返回空数组。
 */
// ── Metrics Snapshot 持久化 ─────────────────────────

/** metrics-history.json 的文件结构 */
interface MetricsHistoryFile {
	snapshots: MetricsSnapshot[];
}

const MAX_METRICS_SNAPSHOTS = 30;

/**
 * 读取 metrics 历史。文件不存在或损坏时返回空数组。
 */
export function loadMetricsHistory(dir: string): MetricsSnapshot[] {
	const filePath = metricsHistoryPath(dir);
	if (!existsSync(filePath)) return [];

	try {
		const raw = readFileSync(filePath, "utf-8");
		const data = JSON.parse(raw) as MetricsHistoryFile;
		return Array.isArray(data.snapshots) ? data.snapshots : [];
	} catch {
		return [];
	}
}

/**
 * 追加一条 snapshot，滑动窗口保留最近 30 条。
 */
export function saveMetricsSnapshot(dir: string, snapshot: MetricsSnapshot): void {
	const history = loadMetricsHistory(dir);
	history.push(snapshot);

	// 滑动窗口：超出上限时删除最老的
	if (history.length > MAX_METRICS_SNAPSHOTS) {
		history.splice(0, history.length - MAX_METRICS_SNAPSHOTS);
	}

	const filePath = metricsHistoryPath(dir);
	writeFileSync(
		filePath,
		JSON.stringify({ snapshots: history }, null, 2),
		"utf-8",
	);
}

// ── History JSONL ────────────────────────────────────

// ── Daily Report 状态 ──────────────────────────────

/** pending.json 中 pending 状态建议的最大数量 */
const MAX_PENDING_SUGGESTIONS = 30;

/**
 * 增量合并新建议到 pending.json。
 * - title 精确匹配去重：已有 pending 建议的 title 与新建议相同时跳过
 * - 容量保护：pending 状态的建议不超过 MAX_PENDING_SUGGESTIONS 条
 * - 无现有文件时创建新 PendingFile
 */
export function mergePending(dir: string, newSuggestions: EvolutionSuggestion[]): void {
	if (newSuggestions.length === 0) return;

	const existing = loadPending(dir);
	if (!existing) {
		const pending: PendingFile = {
			generatedAt: new Date().toISOString(),
			reportUsed: "daily-report",
			suggestions: newSuggestions,
		};
		savePending(dir, pending);
		return;
	}

	// title 去重：跳过与已有 pending 建议同名的
	const pendingTitles = new Set(
		existing.suggestions
			.filter(s => s.status === "pending")
			.map(s => s.title),
	);
	const unique = newSuggestions.filter(s => !pendingTitles.has(s.title));

	if (unique.length > 0) {
		existing.suggestions.push(...unique);
	}

	// 容量保护：超出时将最早的 pending 标记为 rejected
	const pendingCount = existing.suggestions.filter(s => s.status === "pending").length;
	if (pendingCount > MAX_PENDING_SUGGESTIONS) {
		const overflow = pendingCount - MAX_PENDING_SUGGESTIONS;
		let evicted = 0;
		for (const sug of existing.suggestions) {
			if (sug.status === "pending" && evicted < overflow) {
				sug.status = "rejected";
				evicted++;
			}
		}
	}

	savePending(dir, existing);
}

/**
 * 写入每日运行状态文件，供诊断。
 * 文件路径: {dailyReportsDir}/.last-run-status
 */
export function saveLastRunStatus(
	dailyReportsDir: string,
	status: "success" | "failed",
	errorSummary?: string,
): void {
	const filePath = join(dailyReportsDir, ".last-run-status");
	const data = {
		status,
		timestamp: new Date().toISOString(),
		...(errorSummary ? { errorSummary } : {}),
	};
	writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
}

// ── History JSONL ────────────────────────────────────

export function loadHistory(dir: string, limit: number = 10): HistoryEntry[] {
	const filePath = historyPath(dir);
	if (!existsSync(filePath)) return [];

	try {
		const raw = readFileSync(filePath, "utf-8").trim();
		if (raw.length === 0) return [];

		const lines = raw.split("\n");
		const tail = lines.slice(-limit);

		const entries: HistoryEntry[] = [];
		for (const line of tail) {
			const trimmed = line.trim();
			if (trimmed.length === 0) continue;
			try {
				const entry = JSON.parse(trimmed) as HistoryEntry;
				// Migration: 旧格式有 diff 字段而无 instruction
				if (!entry.instruction && (entry as unknown as Record<string, unknown>).diff) {
					entry.instruction = String((entry as unknown as Record<string, unknown>).diff);
					delete (entry as unknown as Record<string, unknown>).diff;
				}
				entries.push(entry);
			} catch {
				// 损坏行跳过
			}
		}
		return entries;
	} catch {
		return [];
	}
}

/**
 * Evolution Engine — 每日报告生成器
 *
 * 将 SignalReport + Suggestions + EffectReview 转换为人类可读的 Markdown 报告。
 */

import type { SignalReport, EvolutionSuggestion, EffectReview } from "./types";

// ── 公共 API ─────────────────────────────────────────

/**
 * 生成每日分析报告的 Markdown 文本。
 * 报告结构：数据概览 → 异常信号 → 趋势变化 → 改进建议 → 效果回顾（条件章节）
 */
export function generateDailyReport(
	signalReport: SignalReport,
	suggestions: EvolutionSuggestion[],
	effectReview?: EffectReview[],
): string {
	const date = new Date(signalReport.generatedAt).toISOString().slice(0, 10);
	const snapshot = signalReport.metricsSnapshot;
	const hasData = snapshot.sessionCount > 0;

	const sections: string[] = [
		`# Evolution Daily Report — ${date}`,
		"",
		"## 数据概览",
		...buildOverview(snapshot, hasData),
		"",
		"## 异常信号",
		...buildAnomalies(signalReport.anomalies),
		"",
		"## 趋势变化",
		...buildTrends(signalReport.trends),
		"",
		"## 改进建议",
		...buildSuggestions(suggestions),
	];

	// 效果回顾：仅有数据时追加
	if (effectReview && effectReview.length > 0) {
		sections.push("", "## 效果回顾", ...buildEffectReview(effectReview));
	}

	return sections.join("\n");
}

// ── 内部格式化函数 ───────────────────────────────────

function buildOverview(
	snapshot: { sessionCount: number; totalToolCalls: number; totalInputTokens: number; totalOutputTokens: number; avgTurnsPerSession: number },
	hasData: boolean,
): string[] {
	if (!hasData) {
		return [
			"- Session 数量：无数据",
			"- 工具调用总数：无数据",
			"- Token 消耗：无数据",
			"- 平均每 session 轮次：无数据",
		];
	}

	return [
		`- Session 数量：${snapshot.sessionCount}`,
		`- 工具调用总数：${snapshot.totalToolCalls}`,
		`- Token 消耗：input ${snapshot.totalInputTokens.toLocaleString()} / output ${snapshot.totalOutputTokens.toLocaleString()}`,
		`- 平均每 session 轮次：${snapshot.avgTurnsPerSession.toFixed(1)}`,
	];
}

function buildAnomalies(anomalies: Array<{ severity: string; detail: string }>): string[] {
	if (anomalies.length === 0) {
		return ["无异常"];
	}

	return anomalies.map(a => `- [${a.severity.toUpperCase()}] ${a.detail}`);
}

function buildTrends(trends: Array<{ field: string; previous: number; current: number; changePercent: number }>): string[] {
	if (trends.length === 0) {
		return ["无显著变化"];
	}

	return trends.map(t => {
		const sign = t.changePercent >= 0 ? "+" : "";
		return `- ${t.field}: ${formatNum(t.previous)} → ${formatNum(t.current)} (${sign}${t.changePercent.toFixed(1)}%)`;
	});
}

function buildSuggestions(suggestions: EvolutionSuggestion[]): string[] {
	if (suggestions.length === 0) {
		return ["系统运行良好，无需调整"];
	}

	const lines: string[] = [];
	for (let i = 0; i < suggestions.length; i++) {
		const s = suggestions[i];
		if (i > 0) lines.push("");
		lines.push(`### #${i} [${s.severity.toUpperCase()}] ${s.title}`);
		if (s.description) lines.push(`- 描述：${s.description}`);
		if (s.rationale) lines.push(`- 依据：${s.rationale}`);
		if (s.targetPath) lines.push(`- 修改目标：${s.targetPath}`);
		if (s.instruction) lines.push(`- 修改指令：${s.instruction}`);
	}
	return lines;
}

function buildEffectReview(reviews: EffectReview[]): string[] {
	return reviews.map(r => {
		const sign = r.changePercent >= 0 ? "+" : "";
		return `- ${r.suggestionTitle}: ${r.targetMetric} ${formatNum(r.before)} → ${formatNum(r.after)} (${sign}${r.changePercent.toFixed(1)}%)`;
	});
}

/** 格式化数字：整数直接显示，浮点保留 2 位 */
function formatNum(n: number): string {
	return Number.isInteger(n) ? String(n) : n.toFixed(2);
}

/**
 * Evolution Engine — 数据垃圾回收
 *
 * 清理过期的 reports、signals、daily 数据文件，防止磁盘无限膨胀。
 * 由 /evolve 命令在每次运行后自动调用。
 */

import { existsSync, readdirSync, unlinkSync, statSync } from "node:fs";
import { join } from "node:path";

// ── GC 策略常量 ──────────────────────────────────────

/** reports/*.json 保留最新 N 个 */
const MAX_REPORTS = 3;

/** signals/*.json 保留最新 N 个 */
const MAX_SIGNALS = 30;

/** daily/*.json 保留天数 */
const MAX_DAILY_DAYS = 90;

/** daily-reports/*.md 保留天数 */
const MAX_DAILY_REPORT_DAYS = 30;

// ── 辅助函数 ─────────────────────────────────────────

/** 安全地按修改时间降序排列目录中的 .json 文件 */
function listJsonByMtime(dir: string): string[] {
	if (!existsSync(dir)) return [];

	try {
		const entries = readdirSync(dir);
		return entries
			.filter(name => name.endsWith(".json"))
			.map(name => ({
				name,
				path: join(dir, name),
				mtime: statSync(join(dir, name)).mtimeMs,
			}))
			.sort((a, b) => b.mtime - a.mtime)
			.map(e => e.path);
	} catch {
		return [];
	}
}

/** 删除指定文件路径列表 */
function removeFiles(paths: string[]): number {
	let removed = 0;
	for (const p of paths) {
		try {
			unlinkSync(p);
			removed++;
		} catch (err) {
			// 文件可能已被其他进程删除，记录但不停滞
			console.warn(`[evolve-gc] Failed to remove ${p}: ${err instanceof Error ? err.message : String(err)}`);
		}
	}
	return removed;
}

/** 从 daily 文件名提取日期并过滤超过 N 天的 */
function listExpiredDaily(dir: string, maxDays: number): string[] {
	if (!existsSync(dir)) return [];

	const cutoff = Date.now() - maxDays * 24 * 60 * 60 * 1000;

	try {
		const entries = readdirSync(dir);
		const expired: string[] = [];

		for (const name of entries) {
			if (!name.endsWith(".json")) continue;

			// daily 文件名格式: 2026-05-27.json
			const dateStr = name.replace(".json", "");
			const fileTime = new Date(dateStr).getTime();

			// 文件名无法解析为日期时，用 mtime 兜底
			const effectiveTime = Number.isNaN(fileTime)
				? statSync(join(dir, name)).mtimeMs
				: fileTime;

			if (effectiveTime < cutoff) {
				expired.push(join(dir, name));
			}
		}

		return expired;
	} catch {
		return [];
	}
}

/** 从 daily-reports 文件名提取日期并过滤超过 N 天的指定扩展名文件 */
function listExpiredDailyByExt(dir: string, maxDays: number, ext: string): string[] {
	if (!existsSync(dir)) return [];

	const cutoff = Date.now() - maxDays * 24 * 60 * 60 * 1000;

	try {
		const entries = readdirSync(dir);
		const expired: string[] = [];

		for (const name of entries) {
			// 排除 dotfile 和不匹配扩展名的文件
			if (!name.endsWith(ext) || name.startsWith(".")) continue;

			// 文件名格式: 2026-05-27.md
			const dateStr = name.replace(ext, "");
			const fileTime = new Date(dateStr).getTime();

			// 文件名无法解析为日期时，用 mtime 兜底
			const effectiveTime = Number.isNaN(fileTime)
				? statSync(join(dir, name)).mtimeMs
				: fileTime;

			if (effectiveTime < cutoff) {
				expired.push(join(dir, name));
			}
		}

		return expired;
	} catch {
		return [];
	}
}

// ── 公共 API ─────────────────────────────────────────

/** GC 清理结果 */
export interface GcResult {
	reportsRemoved: number;
	signalsRemoved: number;
	dailyRemoved: number;
	dailyReportsRemoved: number;
}

/**
 * 执行数据垃圾回收。
 * 目录不存在时静默跳过，不报错。
 */
export function runGc(evolutionDir: string): GcResult {
	const reportsDir = join(evolutionDir, "reports");
	const signalsDir = join(evolutionDir, "signals");
	const dailyDir = join(evolutionDir, "daily");

	// reports: 保留最新 MAX_REPORTS 个
	const reportFiles = listJsonByMtime(reportsDir);
	const reportsToRemove = reportFiles.slice(MAX_REPORTS);
	const reportsRemoved = removeFiles(reportsToRemove);

	// signals: 保留最新 MAX_SIGNALS 个
	const signalFiles = listJsonByMtime(signalsDir);
	const signalsToRemove = signalFiles.slice(MAX_SIGNALS);
	const signalsRemoved = removeFiles(signalsToRemove);

	// daily: 保留 MAX_DAILY_DAYS 天内
	const expiredDaily = listExpiredDaily(dailyDir, MAX_DAILY_DAYS);
	const dailyRemoved = removeFiles(expiredDaily);

	// daily-reports: 保留 MAX_DAILY_REPORT_DAYS 天内的 .md 文件
	let dailyReportsRemoved = 0;
	const dailyReportsDir = join(evolutionDir, "daily-reports");
	if (existsSync(dailyReportsDir)) {
		const expiredReports = listExpiredDailyByExt(dailyReportsDir, MAX_DAILY_REPORT_DAYS, ".md");
		dailyReportsRemoved = removeFiles(expiredReports);
	}

	return { reportsRemoved, signalsRemoved, dailyRemoved, dailyReportsRemoved };
}

/**
 * Evolution Engine — 每日自动分析触发器
 *
 * 在 session_start 中异步触发，每天最多运行一次完整的分析流程。
 * Fire-and-forget：不阻塞 session 初始化。
 *
 * 流程：检查报告 → 获取锁 → 运行 analyzer → summarizer → Judge
 *       → 生成 Markdown 报告 → 合并 pending → 释放锁
 */

import {
	existsSync,
	writeFileSync,
	readFileSync,
	unlinkSync,
	statSync,
	renameSync,
	mkdirSync,
} from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import { execFile } from "node:child_process";

import type { Dirs, JudgeInput, PendingFile, EvolutionSuggestion } from "./types";
import {
	loadPending,
	savePending,
	mergePending,
	saveLastRunStatus,
	loadMetricsHistory,
	loadHistory,
} from "./state";
import { generateDailyReport } from "./report-generator";
import { summarizeReport } from "./summarizer.js";
import { buildEffectReview } from "./effect-tracker.js";
import { runJudge } from "./judge";
import { runGc } from "./gc.js";

// ── 常量 ─────────────────────────────────────────────

/** analyzer 脚本执行超时 */
const ANALYZER_TIMEOUT_MS = 60_000;

const ANALYZER_SCRIPT = join(
	homedir(),
	".pi/agent/scripts/pi-session-analyzer/analyze.py",
);

// ── Lock 管理 ────────────────────────────────────────

interface LockData {
	pid: number;
	timestamp: string;
}

/**
 * 尝试获取锁文件。
 * - 已有锁但 PID 已死 → 清理 stale lock，获取新锁
 * - 已有锁且 PID 存活 → 返回 false
 * - 无锁文件 → 创建并返回 true
 */
function acquireLock(lockPath: string): boolean {
	if (existsSync(lockPath)) {
		try {
			const raw = readFileSync(lockPath, "utf-8");
			const lock = JSON.parse(raw) as LockData;

			// 检查 PID 是否仍然存活
			// process.kill(pid, 0) 不发送信号，只检查进程存在性
			// 注意：此调用假设 Unix 环境（macOS/Linux），Pi 仅在 macOS 上运行
			try {
				process.kill(lock.pid, 0);
				// PID 仍然存活 → 另一个进程在运行
				return false;
			} catch {
				// PID 已死 → stale lock，清理
				unlinkSync(lockPath);
			}
		} catch {
			// 锁文件损坏 → 清理
			unlinkSync(lockPath);
		}
	}

	// 创建新锁
	const data: LockData = { pid: process.pid, timestamp: new Date().toISOString() };
	writeFileSync(lockPath, JSON.stringify(data, null, 2), "utf-8");
	return true;
}

/** 释放锁文件 */
function releaseLock(lockPath: string): void {
	try {
		unlinkSync(lockPath);
	} catch {
		// 锁文件可能已被其他进程清理
	}
}

// ── Pipeline ─────────────────────────────────────────

/**
 * 运行 Python analyzer 生成报告。
 * 返回报告文件路径，失败时抛出错误。
 */
function runAnalyzer(outputPath: string): Promise<string> {
	return new Promise<string>((resolve, reject) => {
		if (!existsSync(ANALYZER_SCRIPT)) {
			reject(new Error(`Session analyzer not found at ${ANALYZER_SCRIPT}`));
			return;
		}

		execFile(
			"python3",
			[ANALYZER_SCRIPT, "--since", "1d", "--format", "json", "--output", outputPath],
			{ timeout: ANALYZER_TIMEOUT_MS },
			(err: Error | null) => {
				if (err) {
					reject(err);
				} else {
					resolve(outputPath);
				}
			},
		);
	});
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 每日自动分析入口。
 * 在 session_start 中调用，fire-and-forget。
 * 同一天只运行一次（通过文件存在性判断）。
 */
export async function checkAndRunDailyAnalysis(dirs: Dirs): Promise<void> {
	const today = new Date().toISOString().slice(0, 10);
	const reportPath = join(dirs.dailyReportsDir, `${today}.md`);

	// AC-2: 同一天不重复生成
	if (existsSync(reportPath) && statSync(reportPath).size > 0) {
		return;
	}

	// 获取锁
	const lockPath = join(dirs.dailyReportsDir, ".daily-report.lock");
	if (!acquireLock(lockPath)) {
		return;
	}

	try {
		// 确保 tmp 目录存在
		if (!existsSync(dirs.tmpDir)) {
			mkdirSync(dirs.tmpDir, { recursive: true });
		}

		// 1. 运行 analyzer
		const tmpReportPath = join(dirs.tmpDir, `daily-raw-${today}.json`);
		await runAnalyzer(tmpReportPath);

		// 2. 读取原始报告
		const rawReport = readFileSync(tmpReportPath, "utf-8");
		const report = JSON.parse(rawReport) as Record<string, unknown>;

		// 3. Summarizer pipeline
		const metricsHistory = loadMetricsHistory(dirs.evolutionDir);
		const signalReport = summarizeReport(
			report,
			metricsHistory,
			dirs.evolutionDir,
			tmpReportPath,
		);

		// 更新内存中的 metrics 历史
		metricsHistory.push(signalReport.metricsSnapshot);

		// 3b. Effect review
		const recentHistory = loadHistory(dirs.evolutionDir, 30);
		const effectReview = buildEffectReview(recentHistory, metricsHistory);
		if (effectReview.length > 0) {
			signalReport.effectReview = effectReview;
		}

		// 3c. GC
		runGc(dirs.evolutionDir);

		// 4. 运行 LLM Judge
		const signalPath = join(
			dirs.signalsDir,
			`signal-${signalReport.metricsSnapshot.date}.json`,
		);
		const judgeInput: JudgeInput = {
			target: "all",
			reportPath: signalPath,
			promptFilePath: "",
		};

		let suggestions: EvolutionSuggestion[];
		try {
			suggestions = await runJudge(judgeInput, dirs.templateDir);
		} catch (err) {
			const msg = err instanceof Error ? err.message : String(err);
			throw new Error(`LLM Judge failed: ${msg}`);
		}

		// 5. 生成 Markdown 报告
		const markdown = generateDailyReport(signalReport, suggestions, effectReview);

		// 6. 原子写入报告文件
		const tmpReport = `${reportPath}.tmp`;
		writeFileSync(tmpReport, markdown, "utf-8");
		renameSync(tmpReport, reportPath);

		// 7. 合并建议到 pending.json
		mergePending(dirs.evolutionDir, suggestions);

		// 8. 记录成功状态
		saveLastRunStatus(dirs.dailyReportsDir, "success");
	} catch (err) {
		// AC-8: 失败不阻塞
		const msg = err instanceof Error ? err.message : String(err);
		console.error(`[evolve] Daily analysis failed: ${msg}`);
		saveLastRunStatus(dirs.dailyReportsDir, "failed", msg);
	} finally {
		releaseLock(lockPath);
	}
}

/**
 * Evolution Engine — Command handler 函数
 *
 * 4 个 handler：handleEvolve, handleEvolveApply, handleEvolveStats, handleEvolveRollback
 * 每个 handler 返回 CommandResult（{ content, details }）。
 * 错误用 throw new Error() 抛出，正常路径返回 CommandResult。
 */

import { existsSync, mkdirSync, readdirSync, readFileSync, statSync, writeFileSync } from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import { execFile } from "node:child_process";

import type {
	Dirs,
	CommandResult,
	EvolveCommandParams,
	EvolveApplyCommandParams,
	StatsData,
	PendingFile,
	EvolutionSuggestion,
	JudgeInput,
} from "./types";
import { runJudge } from "./judge";
import { applySuggestion, rollbackSuggestion } from "./applier";
import { loadPending, savePending, appendHistory, loadHistory, loadMetricsHistory } from "./state";
import { summarizeReport } from "./summarizer.js";
import { buildEffectReview } from "./effect-tracker.js";
import { runGc } from "./gc.js";

// ── 常量 ─────────────────────────────────────────────

const MS_PER_DAY = 86_400_000;
/** analyzer 脚本执行超时 */
const ANALYZER_TIMEOUT_MS = 60_000;

const ANALYZER_SCRIPT = join(
	homedir(),
	".pi/agent/scripts/pi-session-analyzer/analyze.py",
);

// ── 工具函数 ─────────────────────────────────────────

function successResult(text: string, details: Record<string, unknown>): CommandResult {
	return {
		content: [{ type: "text" as const, text }],
		details,
	};
}

/** 检查 reportsDir 下最近 N 天内是否有 JSON 报告 */
function findRecentReport(reportsDir: string, sinceDays: number): string | null {
	if (!existsSync(reportsDir)) return null;

	const cutoff = Date.now() - sinceDays * MS_PER_DAY;
	const files: Array<{ name: string; mtime: number }> = [];

	for (const entry of readdirSync(reportsDir)) {
		if (!entry.endsWith(".json")) continue;
		const filePath = join(reportsDir, entry);
		try {
			const stat = { mtime: getMtimeMs(filePath) };
			if (stat.mtime >= cutoff) {
				files.push({ name: entry, mtime: stat.mtime });
			}
		} catch (err) {
			// 文件可能被其他进程删除，跳过
			if (process.env.NODE_ENV !== "test") console.warn(`[evolve] Failed to stat ${entry}: ${err instanceof Error ? err.message : String(err)}`);
		}
	}

	if (files.length === 0) return null;

	// 取最新的
	files.sort((a, b) => b.mtime - a.mtime);
	return join(reportsDir, files[0].name);
}

function getMtimeMs(filePath: string): number {
	return statSync(filePath).mtimeMs;
}

function parseSinceDays(since: string): number {
	const match = since.match(/^(\d+)d$/);
	if (match) return parseInt(match[1], 10);
	// fallback: 尝试直接当数字
	const n = parseInt(since, 10);
	return Number.isFinite(n) && n > 0 ? n : 7;
}

// ── handleEvolve ─────────────────────────────────────

/**
 * /evolve handler:
 * 1. 查找近期报告（或运行 analyzer 生成）
 * 2. 构建 Judge 输入
 * 3. 运行 LLM Judge
 * 4. 保存 pending.json
 * 5. 返回建议摘要
 */
export async function handleEvolve(
	params: EvolveCommandParams,
	dirs: Dirs,
): Promise<CommandResult> {
	try {
		const sinceDays = parseSinceDays(params.since);

		// 1. 查找近期报告
		let reportPath = findRecentReport(dirs.reportsDir, sinceDays);

		if (!reportPath) {
			// 运行 analyzer 生成报告
			if (!existsSync(dirs.reportsDir)) {
				mkdirSync(dirs.reportsDir, { recursive: true });
			}

			const tmpReportPath = join(
				dirs.reportsDir,
				`phase2-${Date.now()}.json`,
			);

			if (!existsSync(ANALYZER_SCRIPT)) {
				throw new Error(
					`Session analyzer not found at ${ANALYZER_SCRIPT}. ` +
					`Please install pi-session-analyzer first.`
				);
			}

			try {
				await new Promise<void>((resolve, reject) => {
					execFile(
						"python3",
						[ANALYZER_SCRIPT, "--since", params.since, "--format", "json", "--output", tmpReportPath],
						{ timeout: ANALYZER_TIMEOUT_MS },
						(err: Error | null) => err ? reject(err) : resolve(),
					);
				});
				reportPath = tmpReportPath;
			} catch (err) {
				const msg = err instanceof Error ? err.message : String(err);
				throw new Error(`Failed to run session analyzer: ${msg}`);
			}
		}

		// 2. 读取报告
		let report: Record<string, unknown>;
		try {
			const raw = readFileSync(reportPath, "utf-8");
			report = JSON.parse(raw) as Record<string, unknown>;
		} catch (err) {
			const msg = err instanceof Error ? err.message : String(err);
			throw new Error(`Failed to read report: ${msg}`);
		}

		// 3. Signal Summarizer Pipeline
		if (!existsSync(dirs.tmpDir)) {
			mkdirSync(dirs.tmpDir, { recursive: true });
		}

		// 3a. 加载 metrics 历史
		const metricsHistory = loadMetricsHistory(dirs.evolutionDir);

		// 3b. 运行 summarizer（内部会 saveMetricsSnapshot + 写信号文件到 signalsDir）
		const signalReport = summarizeReport(report, metricsHistory, dirs.evolutionDir, reportPath);

		// 3b-2. 将新 snapshot 加入内存历史，让 effect review 看到最新数据
		metricsHistory.push(signalReport.metricsSnapshot);

		// 3c. 构建 effect review 并追加到信号文件
		const recentHistory = loadHistory(dirs.evolutionDir, 30);
		const effectReview = buildEffectReview(recentHistory, metricsHistory);
		if (effectReview.length > 0) {
			signalReport.effectReview = effectReview;
			const effectSignalPath = join(dirs.signalsDir, `signal-${signalReport.metricsSnapshot.date}.json`);
			writeFileSync(effectSignalPath, JSON.stringify(signalReport, null, 2), "utf-8");
		}

		// 3d. GC 清理旧信号文件
		runGc(dirs.evolutionDir);

		// 3e. 构建 Judge input（使用信号文件而非原始报告）
		const signalPath = join(dirs.signalsDir, `signal-${signalReport.metricsSnapshot.date}.json`);
		const judgeInput: JudgeInput = {
			target: params.target === "all" ? "all" : params.target,
			reportPath: signalPath,
			promptFilePath: "",
		};

		// 4. 运行 LLM Judge
		let suggestions: EvolutionSuggestion[];
		try {
			suggestions = await runJudge(judgeInput, dirs.templateDir);
		} catch (err) {
			const msg = err instanceof Error ? err.message : String(err);
			throw new Error(`LLM Judge failed: ${msg}`);
		}

		// 5. 保存 pending.json
		const pending: PendingFile = {
			generatedAt: new Date().toISOString(),
			reportUsed: reportPath,
			suggestions,
		};
		savePending(dirs.evolutionDir, pending);

		// 6. 返回摘要（含 index + title + severity）
		const summaryLines = suggestions
			.map((s, i) => `  #${i} [${s.severity.toUpperCase()}] ${s.title}`)
			.join("\n");

		return successResult(
			`Generated ${suggestions.length} evolution suggestion(s):\n${summaryLines}\n\nUse /evolve-apply action=list to review details, then /evolve-apply action=apply index=<N> or action=skip index=<N> to decide per suggestion.`,
			{
				action: "evolve",
				count: suggestions.length,
				suggestions: suggestions.map((s, i) => ({
					index: i,
					id: s.id,
					title: s.title,
					severity: s.severity,
					confidence: s.confidence,
					target: s.target,
					targetPath: s.targetPath,
					status: s.status,
				})),
			},
		);
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Unexpected error in /evolve: ${msg}`);
	}
}

// ── handleEvolveApply ────────────────────────────────

/**
 * /evolve-apply handler:
 * - "list" (默认): 显示所有 pending 建议，不做任何 apply
 * - "apply" + index: 对指定 index 的建议执行 apply（仅 status === "pending"）
 * - "skip" + index: 对指定 index 的建议标记为 rejected
 */
export async function handleEvolveApply(
	params: EvolveApplyCommandParams,
	dirs: Dirs,
): Promise<CommandResult> {
	try {
		const pending = loadPending(dirs.evolutionDir);
		if (!pending) {
			throw new Error("No pending suggestions found. Run /evolve first.");
		}

		const allSuggestions = pending.suggestions;

		// ── list: 显示所有 pending 建议 ─────────────────
		if (params.action === "list") {
			const pendingItems = allSuggestions
				.map((s, i) => ({ suggestion: s, index: i }))
				.filter(({ suggestion }) => suggestion.status === "pending");

			if (pendingItems.length === 0) {
				return successResult("No pending suggestions. All reviewed or none generated.", {
					action: "list",
				pendingCount: 0,
				suggestions: [],
				});
			}

			const contentLines = pendingItems.map(({ suggestion, index }) => {
				const header = `#${index} [${suggestion.severity.toUpperCase()}] ${suggestion.title}`;
				const desc = suggestion.description ? `  Description: ${suggestion.description}` : "";
				const rationale = suggestion.rationale ? `  Rationale: ${suggestion.rationale}` : "";
				const instruction = suggestion.instruction ? `  Target: ${suggestion.targetPath}` : "";
				const instructionPreview = suggestion.instruction
					? `  Instruction:\n  ${suggestion.instruction.split("\n").slice(0, 10).join("\n  ")}`
					: "";
				return [header, desc, rationale, instruction, instructionPreview].filter(Boolean).join("\n");
			}).join("\n\n");

			return successResult(
				`Pending suggestions (${pendingItems.length}):\n\n${contentLines}`,
				{
					action: "list",
					pendingCount: pendingItems.length,
					suggestions: pendingItems.map(({ suggestion, index }) => ({
						index,
						id: suggestion.id,
						title: suggestion.title,
						severity: suggestion.severity,
						confidence: suggestion.confidence,
						target: suggestion.target,
						targetPath: suggestion.targetPath,
						status: suggestion.status,
						description: suggestion.description,
						rationale: suggestion.rationale,
						instruction: suggestion.instruction,
					})),
				},
			);
		}

		// ── apply/skip: 需要 index 参数 ──────────────────
		if (params.index === undefined) {
			throw new Error(
				`Index is required for "${params.action}" action. Use /evolve-apply action=list first to see indices.`,
			);
		}

		if (params.index < 0 || params.index >= allSuggestions.length) {
			throw new Error(
				`Invalid index: ${params.index}. Valid range: 0-${allSuggestions.length - 1}`,
			);
		}

		const suggestion = allSuggestions[params.index];

		// ── skip: 标记为 rejected ──────────────────────
		if (params.action === "skip") {
			suggestion.status = "rejected";
			savePending(dirs.evolutionDir, pending);

			return successResult(
				`Skipped suggestion #${params.index}: ${suggestion.title}`,
				{
					action: "skip",
					index: params.index,
					suggestionId: suggestion.id,
					title: suggestion.title,
				},
			);
		}

		// ── apply: 只处理 pending 状态 ─────────────────
		if (suggestion.status !== "pending") {
			throw new Error(
				`Suggestion #${params.index} is "${suggestion.status}", not "pending". Only pending suggestions can be applied.`,
			);
		}

		const backupDir = join(dirs.evolutionDir, "backups");
		if (!existsSync(backupDir)) {
			mkdirSync(backupDir, { recursive: true });
		}

		const result = await applySuggestion(suggestion, backupDir);

		if (result.success) {
			suggestion.status = "applied";

			// 获取最新 snapshot 日期，用于后续效果追踪
			const metricsHistory = loadMetricsHistory(dirs.evolutionDir);
			const latestSnapshotDate = metricsHistory.length > 0
				? metricsHistory[metricsHistory.length - 1].date
				: undefined;

			appendHistory(dirs.evolutionDir, {
				timestamp: new Date().toISOString(),
				action: "apply",
				suggestionId: suggestion.id,
				targetPath: suggestion.targetPath,
				backupPath: result.backupPath ?? join(backupDir, `${suggestion.id}.bak`),
				instruction: suggestion.instruction,
				title: suggestion.title,
				commitSha: result.commitSha,
				metricsSnapshotDate: latestSnapshotDate,
			});
		} else {
			suggestion.status = "failed";
		}

		savePending(dirs.evolutionDir, pending);

		const status = result.success ? "Applied" : "Failed";
		return successResult(
			`${status} suggestion #${params.index}: ${suggestion.title}`,
			{
				action: "apply",
				index: params.index,
				suggestionId: suggestion.id,
				title: suggestion.title,
				success: result.success,
				reason: result.reason,
			},
		);
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Unexpected error in /evolve-apply: ${msg}`);
	}
}

// ── handleEvolveStats ────────────────────────────────

/**
 * /evolve-stats handler:
 * 读取 daily/ 最近 7 天数据，聚合统计。
 */
export function handleEvolveStats(evolutionDir: string): CommandResult {
	try {
		const dailyDir = join(evolutionDir, "daily");
		if (!existsSync(dailyDir)) {
			return successResult("No usage data available yet.", {
				action: "stats",
				toolCalls: 0,
				tokenInput: 0,
				tokenOutput: 0,
				topSkills: [],
				topFailures: [],
			});
		}

		const cutoff = Date.now() - 7 * MS_PER_DAY;
		let toolCalls = 0;
		let tokenInput = 0;
		let tokenOutput = 0;
		const skillCounts: Record<string, number> = {};
		const toolFailures: Record<string, { calls: number; failures: number }> = {};

		for (const entry of readdirSync(dailyDir)) {
			if (!entry.endsWith(".json")) continue;
			const filePath = join(dailyDir, entry);

			// 检查文件日期
			const dateStr = entry.replace(".json", "");
			const fileDate = new Date(`${dateStr}T00:00:00Z`);
			if (Number.isNaN(fileDate.getTime()) || fileDate.getTime() < cutoff) continue;

			try {
				const raw = readFileSync(filePath, "utf-8");
				const day = JSON.parse(raw) as {
					toolCalls?: { total?: number; byTool?: Record<string, number>; failures?: Record<string, number> };
					tokenUsage?: { totalInput?: number; totalOutput?: number };
					skillTriggers?: Record<string, number>;
				};

				toolCalls += day.toolCalls?.total ?? 0;
				tokenInput += day.tokenUsage?.totalInput ?? 0;
				tokenOutput += day.tokenUsage?.totalOutput ?? 0;

				if (day.skillTriggers) {
					for (const [name, count] of Object.entries(day.skillTriggers)) {
						skillCounts[name] = (skillCounts[name] ?? 0) + count;
					}
				}

				if (day.toolCalls?.byTool) {
					for (const [tool, calls] of Object.entries(day.toolCalls.byTool)) {
						if (!toolFailures[tool]) toolFailures[tool] = { calls: 0, failures: 0 };
						toolFailures[tool].calls += calls;
					}
				}
				if (day.toolCalls?.failures) {
					for (const [tool, fails] of Object.entries(day.toolCalls.failures)) {
						if (!toolFailures[tool]) toolFailures[tool] = { calls: 0, failures: 0 };
						toolFailures[tool].failures += fails;
					}
				}
			} catch (err) {
				// 损坏文件跳过
				if (process.env.NODE_ENV !== "test") console.warn(`[evolve-stats] Failed to parse ${entry}: ${err instanceof Error ? err.message : String(err)}`);
			}
		}

		// Top skills（按计数降序取前 5）
		const topSkills = Object.entries(skillCounts)
			.sort((a, b) => b[1] - a[1])
			.slice(0, 5)
			.map(([name, count]) => ({ name, count }));

		// Top failures（按失败率降序取前 5，至少 3 次调用）
		const topFailures = Object.entries(toolFailures)
			.filter(([, v]) => v.calls >= 3)
			.sort((a, b) => (b[1].failures / b[1].calls) - (a[1].failures / a[1].calls))
			.slice(0, 5)
			.map(([tool, v]) => ({ tool, rate: v.failures / v.calls }));

		const stats: StatsData = {
			toolCalls,
			tokenInput,
			tokenOutput,
			topSkills,
			topFailures,
		};

		return successResult(
			`Stats: ${toolCalls} tool calls, ${tokenInput.toLocaleString()} tokens in`,
			{ action: "stats", ...stats },
		);
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Failed to read stats: ${msg}`);
	}
}

// ── handleEvolveRollback ─────────────────────────────

/**
 * /evolve-rollback handler:
 * 1. 加载历史
 * 2. 根据 index 选择记录
 * 3. 执行 rollback
 * 4. 记录到 history
 */
export async function handleEvolveRollback(
	index: number,
	dirs: Dirs,
): Promise<CommandResult> {
	try {
		const history = loadHistory(dirs.evolutionDir, 20);
		if (history.length === 0) {
			throw new Error("No evolution history to rollback.");
		}

		// index 是 1-based
		if (index < 1 || index > history.length) {
			throw new Error(`Invalid index: ${index}. Valid range: 1-${history.length}`);
		}

		// 只允许 rollback apply 类型的记录
		const entry = history[index - 1];
		if (!entry) {
			throw new Error(`No history entry at index ${index}.`);
		}

		if (entry.action !== "apply") {
			throw new Error(`Cannot rollback a "${entry.action}" action. Only "apply" actions can be rolled back.`);
		}

		const result = await rollbackSuggestion(entry);

		if (result.success) {
			// 记录 rollback 到 history
			appendHistory(dirs.evolutionDir, {
				timestamp: new Date().toISOString(),
				action: "rollback",
				suggestionId: entry.suggestionId,
				targetPath: entry.targetPath,
				backupPath: entry.backupPath,
				instruction: entry.instruction,
				title: entry.title,
			});

			return successResult(
				`Rolled back: ${entry.title}`,
				{
					action: "rollback",
					suggestionId: entry.suggestionId,
					targetPath: entry.targetPath,
				},
			);
		}

		throw new Error(`Rollback failed: ${result.reason ?? "unknown"}`);
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Unexpected error in /evolve-rollback: ${msg}`);
	}
}

// ── handleEvolveReport ───────────────────────────────

/**
 * /evolve-report handler:
 * - 无参数 → 显示今天的报告
 * - YYYY-MM-DD → 显示指定日期的报告
 * - --list → 列出所有可用报告（最近 10 条）
 */
export function handleEvolveReport(args: string, dirs: Dirs): CommandResult {
	try {
		const trimmed = args.trim();
		const today = new Date().toISOString().slice(0, 10);

		// ── --list: 列出所有报告 ─────────────────────
		if (trimmed === "--list") {
			return listReports(dirs, today);
		}

		// ── 指定日期或今天 ────────────────────────────
		const targetDate = isDateString(trimmed) ? trimmed : today;
		const reportPath = join(dirs.dailyReportsDir, `${targetDate}.md`);

		if (!existsSync(reportPath)) {
			// 如果是今天的报告缺失，提供额外诊断信息
			if (targetDate === today) {
				const statusInfo = readLastRunStatus(dirs.dailyReportsDir);
				const statusLine = statusInfo
					? `\n最后运行状态: ${statusInfo.status} (${statusInfo.timestamp})${statusInfo.errorSummary ? `\n错误: ${statusInfo.errorSummary}` : ""}`
					: "";
				throw new Error(`今天的报告尚未生成。${statusLine}`);
			}
			throw new Error(`${targetDate} 的报告不存在`);
		}

		const content = readFileSync(reportPath, "utf-8");
		return successResult(content, {
			action: "report",
			date: targetDate,
			size: content.length,
		});
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`Unexpected error in /evolve-report: ${msg}`);
	}
}

// ── Report 辅助函数 ─────────────────────────────────

/** 列出所有可用报告 */
function listReports(dirs: Dirs, today: string): CommandResult {
	if (!existsSync(dirs.dailyReportsDir)) {
		return successResult("尚未生成任何报告。", { action: "list", reports: [] });
	}

	const entries = readdirSync(dirs.dailyReportsDir)
		.filter(name => name.endsWith(".md") && !name.startsWith("."))
		.sort()
		.reverse()
		.slice(0, 10);

	if (entries.length === 0) {
		return successResult("尚未生成任何报告。", { action: "list", reports: [] });
	}

	// 读取最后运行状态
	const statusInfo = readLastRunStatus(dirs.dailyReportsDir);
	const todayReport = `${today}.md`;
	const todayExists = entries.some(e => e === todayReport);

	// 检查最近 7 天缺失日期
	const missingDates: string[] = [];
	for (let i = 0; i < 7; i++) {
		const d = new Date(Date.now() - i * MS_PER_DAY).toISOString().slice(0, 10);
		if (!entries.some(e => e === `${d}.md`)) {
			missingDates.push(d);
		}
	}

	const lines: string[] = ["可用报告:"];
	for (const name of entries) {
		const date = name.replace(".md", "");
		const marker = date === today ? " ← 今天" : "";
		lines.push(`  ${date}${marker}`);
	}

	if (statusInfo) {
		lines.push(`\n最后运行: ${statusInfo.status} (${statusInfo.timestamp})`);
	}

	if (!todayExists) {
		lines.push("\n⚠ 今天的报告尚未生成");
	}

	if (missingDates.length > 0) {
		lines.push(`\n最近 7 天缺失: ${missingDates.join(", ")}`);
	}

	return successResult(lines.join("\n"), {
		action: "list",
		reports: entries.map(e => e.replace(".md", "")),
		todayGenerated: todayExists,
		missingDates,
	});
}

interface LastRunStatus {
	status: string;
	timestamp: string;
	errorSummary?: string;
}

/** 读取 .last-run-status 文件 */
function readLastRunStatus(dailyReportsDir: string): LastRunStatus | null {
	const statusPath = join(dailyReportsDir, ".last-run-status");
	if (!existsSync(statusPath)) return null;

	try {
		const raw = readFileSync(statusPath, "utf-8");
		return JSON.parse(raw) as LastRunStatus;
	} catch {
		return null;
	}
}

/** 检查字符串是否匹配 YYYY-MM-DD 格式 */
function isDateString(s: string): boolean {
	return /^\d{4}-\d{2}-\d{2}$/.test(s) && !Number.isNaN(new Date(s).getTime());
}

/**
 * Evolution Engine — Extension 工厂函数
 *
 * 注册：
 *   - session_start 事件：检查自动触发规则，向 session 注入提示
 *   - evolve tool：分析 session 数据，生成进化建议
 *   - evolve-apply tool：应用 pending 建议
 *   - evolve-stats tool：查看统计仪表盘
 *   - evolve-rollback tool：回滚已应用的建议
 */

import { existsSync, mkdirSync } from "node:fs";
import { homedir } from "node:os";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { Text } from "@mariozechner/pi-tui";
import { Type } from "typebox";
import { StringEnum } from "@mariozechner/pi-ai";

import type { Dirs, EvolutionSuggestion } from "./types";
import { checkAutoTriggerRules, cleanExpiredFlags } from "./monitor";
import {
	handleEvolve,
	handleEvolveApply,
	handleEvolveStats,
	handleEvolveRollback,
	handleEvolveReport,
} from "./commands";
import {
	renderSuggestionSummary,
	renderStatsDashboard,
	renderRollbackList,
	renderAutoTriggerHint,
} from "./widget";
import { loadHistory } from "./state";
import { checkAndRunDailyAnalysis } from "./daily-trigger";

// ── 常量 ─────────────────────────────────────────────

const EVOLUTION_DIR = join(homedir(), ".pi/agent/evolution-data");

/** 模板目录：本文件所在 src/ 下的 templates/ */
const TEMPLATE_DIR = (() => {
	// ESM 环境下用 import.meta.url，fallback 到 __dirname（后者在 bundler 模式中不可用）
	try {
		return join(dirname(fileURLToPath(import.meta.url)), "templates");
	} catch {
		// 这个 catch 理论上不会执行（bundler 模式下 import.meta.url 可用）
		return join(process.cwd(), "evolution-engine", "src", "templates");
	}
})();

/** 目录集合 */
function makeDirs(): Dirs {
	const evolutionDir = EVOLUTION_DIR;
	const reportsDir = join(evolutionDir, "reports");
	const tmpDir = join(evolutionDir, "tmp");
	const signalsDir = join(evolutionDir, "signals");
	const dailyReportsDir = join(evolutionDir, "daily-reports");

	// 确保 base 目录和子目录存在
	if (!existsSync(evolutionDir)) {
		mkdirSync(evolutionDir, { recursive: true });
	}
	for (const dir of [signalsDir, dailyReportsDir]) {
		if (!existsSync(dir)) {
			mkdirSync(dir, { recursive: true });
		}
	}

	return {
		evolutionDir,
		reportsDir,
		tmpDir,
		signalsDir,
		dailyReportsDir,
		templateDir: TEMPLATE_DIR,
	};
}

// ── Tool 参数 schema ─────────────────────────────────

const EvolveParams = Type.Object({
	target: StringEnum(["all", "claude-md", "skills", "merge-reviewer"], {
		default: "all",
		description: "Analysis target scope",
	}),
	since: Type.String({
		default: "7d",
		description: 'Time range (e.g. "7d", "14d")',
	}),
	sample: Type.Optional(Type.Number({
		description: "Number of sessions to sample",
	})),
});

const EvolveApplyParams = Type.Object({
	action: StringEnum(["list", "apply", "skip"], {
		default: "list",
		description: "Action: list (default) shows pending suggestions, apply executes one, skip rejects one",
	}),
	index: Type.Optional(Type.Number({
		description: "Suggestion index (0-based). Required for apply/skip actions.",
	})),
});

const EvolveStatsParams = Type.Object({});

const EvolveRollbackParams = Type.Object({
	index: Type.Number({
		description: "History entry index to rollback (1-based)",
	}),
});

// ── Extension Factory ────────────────────────────────

export default function evolutionEngineExtension(pi: ExtensionAPI): void {
	const dirs = makeDirs();

	// ── Event: session_start ───────────────────────────

	pi.on("session_start", async (_event, ctx) => {
		const flags = checkAutoTriggerRules(dirs.evolutionDir);
		cleanExpiredFlags(dirs.evolutionDir);

		if (flags.length > 0) {
			const hint = renderAutoTriggerHint(flags);
			// 通过 session manager 追加提示（参考 usage-tracker 的模式）
			// ctx.ui.notify 在有 UI 时显示 toast
			if (ctx.hasUI) {
				ctx.ui.notify(hint, "info");
			}
		}

		// 每日自动分析：fire-and-forget，不阻塞 session 初始化
		checkAndRunDailyAnalysis(dirs).catch((err) => {
			console.error("[evolve] Daily analysis failed:", err instanceof Error ? err.message : String(err));
		});
	});

	// ── Tool: evolve ───────────────────────────────────

	pi.registerTool({
		name: "evolve",
		label: "Evolve",
		description:
			"Analyze session usage data and generate evolution suggestions. " +
			"Runs a session analyzer to produce a report, then uses an LLM Judge to generate suggestions. " +
			"Suggestions are saved to pending.json for later review via /evolve-apply.",
		promptSnippet: "Self-evolution: analyze usage patterns and suggest improvements",
		promptGuidelines: [
			"[/evolve] Runs analysis and generates suggestions. Does NOT apply anything automatically.",
			"[/evolve-apply] Applies all pending suggestions. Review evolve output first.",
			"[/evolve-stats] Shows usage statistics dashboard for the last 7 days.",
			"[/evolve-rollback N] Rolls back a previously applied suggestion by history index.",
		],
		parameters: EvolveParams,

		async execute(_toolCallId, params, _signal, _onUpdate, _ctx) {
			return await handleEvolve(
				{
					target: params.target as "all" | "claude-md" | "skills" | "merge-reviewer",
					since: params.since,
					sample: params.sample,
				},
				dirs,
			);
		},

		renderCall(args, theme) {
			return new Text(
				theme.fg("toolTitle", theme.bold("evolve ")) +
				theme.fg("muted", `target=${args.target} since=${args.since}`),
				0, 0,
			);
		},

		renderResult(result, _options, theme) {
			const details = result.details as {
				action?: string;
				count?: number;
				suggestions?: Array<{
					id: string;
					title: string;
					severity: string;
					confidence: number;
				}>;
				error?: boolean;
				message?: string;
			} | undefined;

			if (details?.error) {
				return new Text(
					theme.fg("error", `Error: ${details.message ?? "unknown"}`),
					0, 0,
				);
			}

			if (details?.suggestions && Array.isArray(details.suggestions)) {
				const lines: string[] = [
					theme.fg("toolTitle", `Generated ${details.suggestions.length} suggestion(s):`),
				];
				for (let i = 0; i < details.suggestions.length; i++) {
					const s = details.suggestions[i];
					const severity = s.severity.toUpperCase();
					const conf = s.confidence.toFixed(2);
					lines.push(
						`  ${theme.fg("accent", `#${i + 1}`)} [${severity} conf:${conf}] ${s.title}`,
					);
				}
				return new Text(lines.join("\n"), 0, 0);
			}

			// fallback
			const textPart = result.content[0];
			return new Text(
				textPart?.type === "text" ? textPart.text : "evolve completed",
				0, 0,
			);
		},
	});

	// ── Tool: evolve-apply ─────────────────────────────

	pi.registerTool({
		name: "evolve-apply",
		label: "Evolve Apply",
		description:
			"Review and manage evolution suggestions one by one. " +
			"action=list (default) shows all pending suggestions. " +
			"action=apply index=N applies suggestion #N. " +
			"action=skip index=N rejects suggestion #N. " +
			"Run /evolve first to generate suggestions.",
		promptSnippet: "Apply pending evolution suggestions",
		parameters: EvolveApplyParams,

		async execute(_toolCallId, params) {
			return await handleEvolveApply(
				{ action: params.action as "list" | "apply" | "skip", index: params.index },
				dirs,
			);
		},

		renderCall(_args, theme) {
			return new Text(
				theme.fg("toolTitle", theme.bold("evolve-apply")),
				0, 0,
			);
		},

		renderResult(result, _options, theme) {
			const details = result.details as {
				action?: string;
				pendingCount?: number;
				suggestions?: Array<{ index: number; title: string; severity: string; confidence: number; status: string }>;
				success?: boolean;
				reason?: string;
				suggestionId?: string;
				title?: string;
				error?: boolean;
				message?: string;
			} | undefined;

			if (details?.error) {
				return new Text(
					theme.fg("error", `Error: ${details.message ?? "unknown"}`),
					0, 0,
				);
			}

			const lines: string[] = [];

			if (details?.action === "list") {
				lines.push(theme.fg("toolTitle", `Pending suggestions (${details.pendingCount ?? 0}):`));
				if (details.suggestions) {
					for (const s of details.suggestions) {
						const severity = s.severity.toUpperCase();
						const conf = s.confidence.toFixed(2);
						lines.push(
							`  ${theme.fg("accent", `#${s.index}`)} [${severity} conf:${conf}] ${s.title}`,
						);
					}
				}
				if ((details.pendingCount ?? 0) > 0) {
					lines.push("");
					lines.push(theme.fg("dim", "Use /evolve-apply action=apply index=<N> or action=skip index=<N>"));
				}
			} else if (details?.action === "apply") {
				const icon = details.success
					? theme.fg("success", "\u2713")
					: theme.fg("error", "\u2717");
				const suffix = details.reason ? theme.fg("dim", ` (${details.reason})`) : "";
				lines.push(`${icon} Applied #${details.suggestionId ?? "?"} ${details.title ?? ""}${suffix}`);
			} else if (details?.action === "skip") {
				lines.push(theme.fg("dim", `\u2298 Skipped #${details.suggestionId ?? "?"} ${details.title ?? ""}`));
			}

			if (lines.length === 0) {
				const textPart = result.content[0];
				return new Text(
					textPart?.type === "text" ? textPart.text : "evolve-apply completed",
					0, 0,
				);
			}

			return new Text(lines.join("\n"), 0, 0);
		},
	});

	// ── Tool: evolve-stats ─────────────────────────────

	pi.registerTool({
		name: "evolve-stats",
		label: "Evolve Stats",
		description:
			"Show usage statistics dashboard for the last 7 days. " +
			"Displays tool call counts, token usage, top skills, and high-failure-rate tools.",
		promptSnippet: "View evolution usage stats dashboard",
		parameters: EvolveStatsParams,

		async execute() {
			return handleEvolveStats(dirs.evolutionDir);
		},

		renderCall(_args, theme) {
			return new Text(
				theme.fg("toolTitle", theme.bold("evolve-stats")),
				0, 0,
			);
		},

		renderResult(result, _options, _theme) {
			const textPart = result.content[0];
			return new Text(
				textPart?.type === "text" ? textPart.text : "stats completed",
				0, 0,
			);
		},
	});

	// ── Tool: evolve-rollback ──────────────────────────

	pi.registerTool({
		name: "evolve-rollback",
		label: "Evolve Rollback",
		description:
			"Rollback a previously applied evolution suggestion by history index. " +
			"Use /evolve-rollback without index to list recent history first.",
		promptSnippet: "Rollback an applied evolution suggestion",
		parameters: EvolveRollbackParams,

		async execute(_toolCallId, params) {
			return await handleEvolveRollback(params.index, dirs);
		},

		renderCall(args, theme) {
			return new Text(
				theme.fg("toolTitle", theme.bold("evolve-rollback ")) +
				theme.fg("accent", `#${args.index}`),
				0, 0,
			);
		},

		renderResult(result, _options, theme) {
			const details = result.details as {
				action?: string;
				suggestionId?: string;
				targetPath?: string;
				error?: boolean;
				message?: string;
			} | undefined;

			if (details?.error) {
				return new Text(
					theme.fg("error", `Error: ${details.message ?? "unknown"}`),
					0, 0,
				);
			}

			const textPart = result.content[0];
			return new Text(
				textPart?.type === "text" ? textPart.text : "rollback completed",
				0, 0,
			);
		},
	});

	// ── Command: /evolve ───────────────────────────────

	pi.registerCommand("evolve", {
		description:
			"Analyze usage data and suggest improvements. " +
			"Usage: /evolve [target] [since] | target: all|claude-md|skills|merge-reviewer, since: 7d",
		handler: async (args, ctx) => {
			// 解析简单参数
			const parts = args.trim().split(/\s+/);
			let target: "all" | "claude-md" | "skills" | "merge-reviewer" = "all";
			let since = "7d";

			for (const part of parts) {
				if (part === "all" || part === "claude-md" || part === "skills" || part === "merge-reviewer") {
					target = part;
				} else if (part.match(/^\d+d$/)) {
					since = part;
				}
			}

			// 通过 sendMessage 注入一个 tool call 触发
			// command handler 中无法直接调用 registerTool 的 execute，
			// 但可以通过注入提示词让 AI 调用 evolve tool
			if (ctx.hasUI) {
				ctx.ui.notify(
					`Running evolution analysis (target=${target}, since=${since})...`,
					"info",
				);
			}

			// 直接执行 handler 并打印结果
			const result = await handleEvolve(
				{ target, since, sample: undefined },
				dirs,
			);

			const textPart = result.content[0];
			if (textPart?.type === "text" && ctx.hasUI) {
				ctx.ui.notify(textPart.text, "info");
			}
		},
	});

	// ── Command: /evolve-apply ──────────────────────────

	pi.registerCommand("evolve-apply", {
		description:
			"Review and manage evolution suggestions. " +
			"Usage: /evolve-apply [list|apply|skip] [index]",
		handler: async (args, ctx) => {
			const parts = args.trim().split(/\s+/);
			let action: "list" | "apply" | "skip" = "list";
			let index: number | undefined;

			for (const part of parts) {
				if (part === "list" || part === "apply" || part === "skip") {
					action = part;
				} else {
					const n = parseInt(part, 10);
					if (!Number.isNaN(n) && n >= 0) index = n;
				}
			}

			const result = await handleEvolveApply({ action, index }, dirs);
			const textPart = result.content[0];
			if (textPart?.type === "text" && ctx.hasUI) {
				ctx.ui.notify(textPart.text, "info");
			}
		},
	});

	// ── Command: /evolve-stats ─────────────────────────

	pi.registerCommand("evolve-stats", {
		description: "Show usage statistics dashboard for the last 7 days.",
		handler: async (_args, ctx) => {
			const result = handleEvolveStats(dirs.evolutionDir);
			const textPart = result.content[0];
			if (textPart?.type === "text" && ctx.hasUI) {
				ctx.ui.notify(textPart.text, "info");
			}
		},
	});

	// ── Command: /evolve-rollback ──────────────────────

	pi.registerCommand("evolve-rollback", {
		description:
			"Rollback an applied evolution suggestion. " +
			"Usage: /evolve-rollback [index] | No index to list history.",
		handler: async (args, ctx) => {
			const index = parseInt(args.trim(), 10);

			// 无有效 index 时，显示历史列表
			if (Number.isNaN(index) || index < 1) {
				const history = loadHistory(dirs.evolutionDir, 20);
				const text = renderRollbackList(history);
				if (ctx.hasUI) {
					ctx.ui.notify(text, "info");
				}
				return;
			}

			const result = await handleEvolveRollback(index, dirs);
			const textPart = result.content[0];
			if (textPart?.type === "text" && ctx.hasUI) {
				ctx.ui.notify(textPart.text, "info");
			}
		},
	});
	// ── Tool: evolve-report ────────────────────────────

	const EvolveReportParams = Type.Object({
		args: Type.String({
			default: "",
			description: "Date (YYYY-MM-DD) or --list",
		}),
	});

	pi.registerTool({
		name: "evolve-report",
		label: "Evolve Report",
		description:
			"View daily evolution reports. " +
			"No args shows today's report, YYYY-MM-DD shows a specific date, --list lists all reports.",
		promptSnippet: "View evolution daily report",
		parameters: EvolveReportParams,

		async execute(_toolCallId, params) {
			return handleEvolveReport(params.args, dirs);
		},

		renderCall(args, theme) {
			return new Text(
				theme.fg("toolTitle", theme.bold("evolve-report ")) +
				theme.fg("muted", args.args || "today"),
				0, 0,
			);
		},

		renderResult(result, _options, _theme) {
			const textPart = result.content[0];
			return new Text(
				textPart?.type === "text" ? textPart.text : "evolve-report completed",
				0, 0,
			);
		},
	});

	// ── Command: /evolve-report ────────────────────────

	pi.registerCommand("evolve-report", {
		description:
			"View daily evolution reports. " +
			"Usage: /evolve-report [YYYY-MM-DD] | --list",
		handler: async (args, _ctx) => {
			pi.sendUserMessage(
				`Please call the evolve-report tool with args="${args.trim()}". Do not add any commentary, just call the tool directly.`,
			);
		},
	});

